89	void merge_for_sort(std::vector<int>& items_to_sort, int left, int mid, int right) {
90	    int n1 = mid - left + 1;
91	    int n2 = right - mid;
92	    std::vector<int> L_half(n1), R_half(n2);
93	    for (int i = 0; i < n1; i++) L_half[i] = items_to_sort[left + i];
94	    for (int j = 0; j < n2; j++) R_half[j] = items_to_sort[mid + 1 + j];
95	
96	    int i = 0, j = 0, k = left;
97	    while (i < n1 && j < n2) {
98	        char cmp_res = compare_single_items(L_half[i], R_half[j]);
99	        if (cmp_res == '<' || cmp_res == '=') {
100	            items_to_sort[k++] = L_half[i++];
101	        } else {
102	            items_to_sort[k++] = R_half[j++];
103	        }
104	    }
105	    while (i < n1) items_to_sort[k++] = L_half[i++];
106	    while (j < n2) items_to_sort[k++] = R_half[j++];
107	}
