            int grp1_idx = group_dist(rng_engine);
            int grp2_idx = group_dist(rng_engine);
            if (grp1_idx == grp2_idx) continue;
            if (group_items_indices[grp1_idx].empty() || group_items_indices[grp2_idx].empty()) continue;

            int item1 = group_items_indices[grp1_idx][rng_engine() % group_items_indices[grp1_idx].size()];
            int item2 = group_items_indices[grp2_idx][rng_engine() % group_items_indices[grp2_idx].size()];

            long long w1 = estimated_weights[item1];
            long long w2 = estimated_weights[item2];

            long long old_sum_grp1 = group_sums_array[grp1_idx];
