                        if (w_pk_1 > w_pk_2 && w_pk_2 > 0 && w_pk_2 != 0) {
                            estimated_weights[i] = std::max(1LL, w_pk_1 * w_pk_1 / w_pk_2);
                        } else {
                            estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
                        }
                     } else {
                         estimated_weights[i] = std::max(1LL, w_pk_1 * FACTOR_GT_NUM / 100);
                     }
                } else {
                    long long w_prev_p = estimated_weights[sorted_pivot_item_indices[insert_pos_arr_idx-1]];
                    long long w_next_p = estimated_weights[sorted_pivot_item_indices[insert_pos_arr_idx]];
                    if (w_prev_p > 0 && w_next_p > 0) {
                        estimated_weights[i] = static_cast<long long>(std::sqrt(static_cast<double>(w_prev_p) * w_next_p));
                    } else {
                        estimated_weights[i] = (w_prev_p + w_next_p) / 2;
                    }
                    estimated_weights[i] = std::max(w_prev_p, estimated_weights[i]);
                    estimated_weights[i] = std::min(w_next_p, estimated_weights[i]);
                }
                if (estimated_weights[i] <=0) estimated_weights[i] = 1;
            }
        }
    }

    for(int i=0; i<N_items_global; ++i) {
        if (estimated_weights[i] <= 0) {
            estimated_weights[i] = BASE_WEIGHT;
        }
    }

    // --- Use remaining queries to refine: sort items within buckets ---
    // Group items by their bucket position, then sort them within each bucket
    // This gives us a complete rank ordering to use with order statistics

    // First, build the full sorted order using what we know
    // Pivots are already sorted. Non-pivot items have bucket positions.
    // We can sort items within each bucket using remaining queries.

    if (queries_made < Q_total_global && k_pivots_chosen >= 2) {
        // Build bucket lists
        std::set<int> pivot_set_for_refine(sorted_pivot_item_indices.begin(), sorted_pivot_item_indices.end());
        std::vector<std::vector<int>> buckets(k_pivots_chosen + 1);

        for (int i = 0; i < N_items_global; i++) {
            if (pivot_set_for_refine.count(i)) continue;
            if (item_insert_pos[i] >= 0) {
                buckets[item_insert_pos[i]].push_back(i);
            }
            // items equal to a pivot don't need sorting
        }

        // Sort each bucket that has >1 item (uses merge sort which uses cached comparisons)
        for (int b = 0; b <= k_pivots_chosen && queries_made < Q_total_global; b++) {
            if (buckets[b].size() > 1) {
                merge_sort_items(buckets[b], 0, (int)buckets[b].size() - 1);
            }
        }

        // Now we have a complete ordering. Assign weights using order statistics.
        // Build the full sorted list
        std::vector<int> full_sorted_order;
        std::vector<std::vector<int>> pivot_equal_items(k_pivots_chosen);

        for (int i = 0; i < N_items_global; i++) {
            if (pivot_set_for_refine.count(i)) continue;
            if (item_equal_pivot[i] >= 0) {
                pivot_equal_items[item_equal_pivot[i]].push_back(i);
            }
        }

        for (int b = 0; b <= k_pivots_chosen; b++) {
            // Add bucket items (already sorted)
            for (int item : buckets[b]) {
                full_sorted_order.push_back(item);
            }
            // Add pivot at position b and its equal items
            if (b < k_pivots_chosen) {
                full_sorted_order.push_back(sorted_pivot_item_indices[b]);
                for (int item : pivot_equal_items[b]) {
                    full_sorted_order.push_back(item);
                }
            }
        }

        // Assign weights using exponential order statistics
        int total_items = (int)full_sorted_order.size();
        if (total_items == N_items_global) {
            for (int rank = 0; rank < total_items; rank++) {
                int item = full_sorted_order[rank];
                double expected_w = compute_expected_order_stat(rank + 1, N_items_global);
                estimated_weights[item] = std::max(1LL, (long long)std::round(expected_w));
            }
        }
    }

    // Exhaust remaining queries
    int dummy_item_0_idx = 0;
    int dummy_item_1_idx = 1;
    while(queries_made < Q_total_global) {
        perform_query_actual({dummy_item_0_idx}, {dummy_item_1_idx});
        dummy_item_1_idx = (dummy_item_1_idx + 1) % N_items_global;
        if (dummy_item_1_idx == dummy_item_0_idx) {
            dummy_item_1_idx = (dummy_item_1_idx + 1) % N_items_global;
        }
    }

    // --- Assignment Phase: Guided SA with directed moves ---

    std::vector<int> items_sorted_desc(N_items_global);
    std::iota(items_sorted_desc.begin(), items_sorted_desc.end(), 0);
    std::sort(items_sorted_desc.begin(), items_sorted_desc.end(), [&](int a, int b) {
        return estimated_weights[a] > estimated_weights[b];
    });

    std::vector<int> assignment_array(N_items_global);
    std::vector<long long> group_sums_array(D_groups_global, 0);
    long long total_sum_est_val = 0;
    std::vector<std::vector<int>> group_items_indices(D_groups_global);

    // Snake/zigzag draft
    {
        int group_idx = 0;
        int direction = 1;
        for (int i = 0; i < N_items_global; i++) {
            int item_actual_idx = items_sorted_desc[i];
            assignment_array[item_actual_idx] = group_idx;
            group_sums_array[group_idx] += estimated_weights[item_actual_idx];
            group_items_indices[group_idx].push_back(item_actual_idx);

            group_idx += direction;
            if (group_idx >= D_groups_global) {
                group_idx = D_groups_global - 1;
                direction = -1;
            } else if (group_idx < 0) {
                group_idx = 0;
                direction = 1;
            }
        }
    }

    for (int i = 0; i < N_items_global; i++) {
        total_sum_est_val += estimated_weights[i];
    }

    // Also compute greedy LPT
    std::vector<int> greedy_assignment(N_items_global);
    std::vector<long long> greedy_group_sums(D_groups_global, 0);
    std::vector<std::vector<int>> greedy_group_items(D_groups_global);

    for (int i = 0; i < N_items_global; i++) {
        int item_actual_idx = items_sorted_desc[i];
        int best_grp = 0;
        long long min_sum = greedy_group_sums[0];
        for (int j = 1; j < D_groups_global; j++) {
            if (greedy_group_sums[j] < min_sum) {
                min_sum = greedy_group_sums[j];
                best_grp = j;
            }
        }
        greedy_assignment[item_actual_idx] = best_grp;
        greedy_group_sums[best_grp] += estimated_weights[item_actual_idx];
        greedy_group_items[best_grp].push_back(item_actual_idx);
    }

    double snake_sum_sq = 0, greedy_sum_sq = 0;
    for (int g = 0; g < D_groups_global; g++) {
        snake_sum_sq += static_cast<double>(group_sums_array[g]) * group_sums_array[g];
        greedy_sum_sq += static_cast<double>(greedy_group_sums[g]) * greedy_group_sums[g];
    }
    double snake_var = calculate_variance_from_sums(snake_sum_sq, static_cast<double>(total_sum_est_val), D_groups_global);
    double greedy_var = calculate_variance_from_sums(greedy_sum_sq, static_cast<double>(total_sum_est_val), D_groups_global);

    if (greedy_var < snake_var) {
        assignment_array = greedy_assignment;
        group_sums_array = greedy_group_sums;
        group_items_indices = greedy_group_items;
    }

    double current_sum_sq_group_totals = 0;
    for (long long s : group_sums_array) {
        current_sum_sq_group_totals += static_cast<double>(s) * s;
    }
    double current_var = calculate_variance_from_sums(current_sum_sq_group_totals, static_cast<double>(total_sum_est_val), D_groups_global);

    std::vector<int> best_assignment = assignment_array;
    double best_var = current_var;

    // SA with guided moves
    double T_initial = std::max(1.0, current_var * 0.1);
    if (total_sum_est_val > 0 && current_var < 1e-9) {
        T_initial = std::max(1.0, static_cast<double>(total_sum_est_val) / std::max(1, N_items_global) * 0.1);
    }
    if (D_groups_global <= 1) T_initial = 0;

    double T = T_initial;
    double T_min = 1e-10;

    std::uniform_real_distribution<double> unif_dist(0.0, 1.0);
    std::uniform_int_distribution<int> item_dist(0, N_items_global - 1);
    std::uniform_int_distribution<int> group_dist(0, D_groups_global - 1);

    int sa_iters_count = 0;
    const int CHECK_TIME_INTERVAL = 512;

    std::vector<int> item_pos_in_group_vector(N_items_global);
    for (int g = 0; g < D_groups_global; g++) {
        for (int pos = 0; pos < (int)group_items_indices[g].size(); pos++) {
            item_pos_in_group_vector[group_items_indices[g][pos]] = pos;
        }
    }

    while (D_groups_global > 1 && N_items_global > 0) {
        sa_iters_count++;
        if (sa_iters_count % CHECK_TIME_INTERVAL == 0) {
            auto time_now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(time_now - program_start_time) >= time_limit_ms) {
                break;
            }
            double elapsed_ms = std::chrono::duration_cast<std::chrono::microseconds>(time_now - program_start_time).count() / 1000.0;
            double progress = elapsed_ms / 1850.0;
            if (progress > 1.0) progress = 1.0;
            T = T_initial * std::pow(T_min / T_initial, progress);
        }

        if (T < 1e-15 && current_var < 1.0 + 1e-9) break;

        int move_choice = rng_engine() % 10;

        if (move_choice < 4) {
            // GUIDED RELOCATE
            int heavy_grp = 0, light_grp = 0;
            long long max_sum = group_sums_array[0], min_sum = group_sums_array[0];
            for (int g = 1; g < D_groups_global; g++) {
                if (group_sums_array[g] > max_sum) { max_sum = group_sums_array[g]; heavy_grp = g; }
                if (group_sums_array[g] < min_sum) { min_sum = group_sums_array[g]; light_grp = g; }
            }

            if (heavy_grp == light_grp || group_items_indices[heavy_grp].empty()) {
                continue;
            }

            long long target_w = (max_sum - min_sum) / 2;
            int best_item = -1;
            long long best_diff = LLONG_MAX;
            for (int item_idx : group_items_indices[heavy_grp]) {
                long long diff = std::abs(estimated_weights[item_idx] - target_w);
                if (diff < best_diff) {
                    best_diff = diff;
                    best_item = item_idx;
                }
            }

            if (best_item == -1) continue;

            int item_to_move_idx = best_item;
            int old_grp_idx = heavy_grp;
            int new_grp_idx = light_grp;
            long long item_w_val = estimated_weights[item_to_move_idx];

            long long old_sum_grp_A = group_sums_array[old_grp_idx];
            long long old_sum_grp_B = group_sums_array[new_grp_idx];
            long long new_sum_grp_A = old_sum_grp_A - item_w_val;
            long long new_sum_grp_B = old_sum_grp_B + item_w_val;

            double new_sum_sq = current_sum_sq_group_totals;
            new_sum_sq -= static_cast<double>(old_sum_grp_A)*old_sum_grp_A + static_cast<double>(old_sum_grp_B)*old_sum_grp_B;
            new_sum_sq += static_cast<double>(new_sum_grp_A)*new_sum_grp_A + static_cast<double>(new_sum_grp_B)*new_sum_grp_B;
            double new_var = calculate_variance_from_sums(new_sum_sq, static_cast<double>(total_sum_est_val), D_groups_global);

            double delta_V = new_var - current_var;

            if (delta_V < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta_V / T))) {
                current_var = new_var;
                current_sum_sq_group_totals = new_sum_sq;
                group_sums_array[old_grp_idx] = new_sum_grp_A;
                group_sums_array[new_grp_idx] = new_sum_grp_B;
                assignment_array[item_to_move_idx] = new_grp_idx;

                int pos = item_pos_in_group_vector[item_to_move_idx];
                if (!group_items_indices[old_grp_idx].empty()) {
                    int last = group_items_indices[old_grp_idx].back();
                    if (item_to_move_idx != last) {
                        group_items_indices[old_grp_idx][pos] = last;
                        item_pos_in_group_vector[last] = pos;
                    }
                    group_items_indices[old_grp_idx].pop_back();
                }
                group_items_indices[new_grp_idx].push_back(item_to_move_idx);
                item_pos_in_group_vector[item_to_move_idx] = group_items_indices[new_grp_idx].size() - 1;

                if (new_var < best_var) {
                    best_var = new_var;
                    best_assignment = assignment_array;
                }
            }
        } else if (move_choice < 6) {
            // GUIDED SWAP
            int heavy_grp = 0, light_grp = 0;
            long long max_sum = group_sums_array[0], min_sum = group_sums_array[0];
            for (int g = 1; g < D_groups_global; g++) {
                if (group_sums_array[g] > max_sum) { max_sum = group_sums_array[g]; heavy_grp = g; }
                if (group_sums_array[g] < min_sum) { min_sum = group_sums_array[g]; light_grp = g; }
            }

            if (heavy_grp == light_grp || group_items_indices[heavy_grp].empty() || group_items_indices[light_grp].empty()) {
                continue;
            }

            long long target_diff = (max_sum - min_sum) / 2;
            int best_h_item = -1, best_l_item = -1;
            long long best_diff = LLONG_MAX;

            int h_samples = std::min((int)group_items_indices[heavy_grp].size(), 8);
            int l_samples = std::min((int)group_items_indices[light_grp].size(), 8);

            for (int hi = 0; hi < h_samples; hi++) {
                int h_idx = hi < (int)group_items_indices[heavy_grp].size() ? hi : rng_engine() % group_items_indices[heavy_grp].size();
                int h_item = group_items_indices[heavy_grp][h_idx];
                for (int li = 0; li < l_samples; li++) {
                    int l_idx = li < (int)group_items_indices[light_grp].size() ? li : rng_engine() % group_items_indices[light_grp].size();
                    int l_item = group_items_indices[light_grp][l_idx];
                    long long w_diff = estimated_weights[h_item] - estimated_weights[l_item];
                    long long diff = std::abs(w_diff - target_diff);
                    if (diff < best_diff && w_diff > 0) {
                        best_diff = diff;
                        best_h_item = h_item;
                        best_l_item = l_item;
                    }
                }
            }

            if (best_h_item == -1 || best_l_item == -1) continue;

            int grp1_idx = heavy_grp;
            int grp2_idx = light_grp;
            int item1 = best_h_item;
            int item2 = best_l_item;
            long long w1 = estimated_weights[item1];
            long long w2 = estimated_weights[item2];

            long long old_sum_grp1 = group_sums_array[grp1_idx];
            long long old_sum_grp2 = group_sums_array[grp2_idx];
            long long new_sum_grp1 = old_sum_grp1 - w1 + w2;
            long long new_sum_grp2 = old_sum_grp2 - w2 + w1;

            double new_sum_sq = current_sum_sq_group_totals;
            new_sum_sq -= static_cast<double>(old_sum_grp1)*old_sum_grp1 + static_cast<double>(old_sum_grp2)*old_sum_grp2;
            new_sum_sq += static_cast<double>(new_sum_grp1)*new_sum_grp1 + static_cast<double>(new_sum_grp2)*new_sum_grp2;
            double new_var = calculate_variance_from_sums(new_sum_sq, static_cast<double>(total_sum_est_val), D_groups_global);

            double delta_V = new_var - current_var;

            if (delta_V < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta_V / T))) {
                current_var = new_var;
                current_sum_sq_group_totals = new_sum_sq;
                group_sums_array[grp1_idx] = new_sum_grp1;
                group_sums_array[grp2_idx] = new_sum_grp2;

                assignment_array[item1] = grp2_idx;
                assignment_array[item2] = grp1_idx;

                int pos1 = item_pos_in_group_vector[item1];
                int back1 = group_items_indices[grp1_idx].back();
                if (item1 != back1) {
                    group_items_indices[grp1_idx][pos1] = back1;
                    item_pos_in_group_vector[back1] = pos1;
                }
                group_items_indices[grp1_idx].pop_back();

                int pos2 = item_pos_in_group_vector[item2];
                int back2 = group_items_indices[grp2_idx].back();
                if (item2 != back2) {
                    group_items_indices[grp2_idx][pos2] = back2;
                    item_pos_in_group_vector[back2] = pos2;
                }
                group_items_indices[grp2_idx].pop_back();

                group_items_indices[grp2_idx].push_back(item1);
                item_pos_in_group_vector[item1] = group_items_indices[grp2_idx].size() - 1;

                group_items_indices[grp1_idx].push_back(item2);
                item_pos_in_group_vector[item2] = group_items_indices[grp1_idx].size() - 1;

                if (new_var < best_var) {
                    best_var = new_var;
                    best_assignment = assignment_array;
                }
            }
        } else if (move_choice < 8) {
            // RANDOM RELOCATE
            int item_to_move_idx = item_dist(rng_engine);
            int old_grp_idx = assignment_array[item_to_move_idx];
            int new_grp_idx = group_dist(rng_engine);
            if (new_grp_idx == old_grp_idx) continue;

            long long item_w_val = estimated_weights[item_to_move_idx];

            long long old_sum_grp_A = group_sums_array[old_grp_idx];
            long long old_sum_grp_B = group_sums_array[new_grp_idx];
            long long new_sum_grp_A = old_sum_grp_A - item_w_val;
            long long new_sum_grp_B = old_sum_grp_B + item_w_val;

            double new_sum_sq = current_sum_sq_group_totals;
            new_sum_sq -= static_cast<double>(old_sum_grp_A)*old_sum_grp_A + static_cast<double>(old_sum_grp_B)*old_sum_grp_B;
            new_sum_sq += static_cast<double>(new_sum_grp_A)*new_sum_grp_A + static_cast<double>(new_sum_grp_B)*new_sum_grp_B;
            double new_var = calculate_variance_from_sums(new_sum_sq, static_cast<double>(total_sum_est_val), D_groups_global);

            double delta_V = new_var - current_var;

            if (delta_V < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta_V / T))) {
                current_var = new_var;
                current_sum_sq_group_totals = new_sum_sq;
                group_sums_array[old_grp_idx] = new_sum_grp_A;
                group_sums_array[new_grp_idx] = new_sum_grp_B;
                assignment_array[item_to_move_idx] = new_grp_idx;

                int pos = item_pos_in_group_vector[item_to_move_idx];
                if (!group_items_indices[old_grp_idx].empty()) {
                    int last = group_items_indices[old_grp_idx].back();
                    if (item_to_move_idx != last) {
                        group_items_indices[old_grp_idx][pos] = last;
                        item_pos_in_group_vector[last] = pos;
                    }
                    group_items_indices[old_grp_idx].pop_back();
                }
                group_items_indices[new_grp_idx].push_back(item_to_move_idx);
                item_pos_in_group_vector[item_to_move_idx] = group_items_indices[new_grp_idx].size() - 1;

                if (new_var < best_var) {
                    best_var = new_var;
                    best_assignment = assignment_array;
                }
            }
        } else {
            // RANDOM SWAP
            int grp1_idx = group_dist(rng_engine);
            int grp2_idx = group_dist(rng_engine);
            if (grp1_idx == grp2_idx) continue;
            if (group_items_indices[grp1_idx].empty() || group_items_indices[grp2_idx].empty()) continue;

            int item1 = group_items_indices[grp1_idx][rng_engine() % group_items_indices[grp1_idx].size()];
            int item2 = group_items_indices[grp2_idx][rng_engine() % group_items_indices[grp2_idx].size()];

            long long w1 = estimated_weights[item1];
            long long w2 = estimated_weights[item2];

            long long old_sum_grp1 = group_sums_array[grp1_idx];
            long long old_sum_grp2 = group_sums_array[grp2_idx];
            long long new_sum_grp1 = old_sum_grp1 - w1 + w2;
            long long new_sum_grp2 = old_sum_grp2 - w2 + w1;

            double new_sum_sq = current_sum_sq_group_totals;
            new_sum_sq -= static_cast<double>(old_sum_grp1)*old_sum_grp1 + static_cast<double>(old_sum_grp2)*old_sum_grp2;
            new_sum_sq += static_cast<double>(new_sum_grp1)*new_sum_grp1 + static_cast<double>(new_sum_grp2)*new_sum_grp2;
            double new_var = calculate_variance_from_sums(new_sum_sq, static_cast<double>(total_sum_est_val), D_groups_global);

            double delta_V = new_var - current_var;

            if (delta_V < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta_V / T))) {
                current_var = new_var;
                current_sum_sq_group_totals = new_sum_sq;
                group_sums_array[grp1_idx] = new_sum_grp1;
                group_sums_array[grp2_idx] = new_sum_grp2;

                assignment_array[item1] = grp2_idx;
                assignment_array[item2] = grp1_idx;

                int pos1 = item_pos_in_group_vector[item1];
                int back1 = group_items_indices[grp1_idx].back();
                if (item1 != back1) {
                    group_items_indices[grp1_idx][pos1] = back1;
                    item_pos_in_group_vector[back1] = pos1;
                }
                group_items_indices[grp1_idx].pop_back();

                int pos2 = item_pos_in_group_vector[item2];
                int back2 = group_items_indices[grp2_idx].back();
                if (item2 != back2) {
                    group_items_indices[grp2_idx][pos2] = back2;
                    item_pos_in_group_vector[back2] = pos2;
                }
                group_items_indices[grp2_idx].pop_back();

                group_items_indices[grp2_idx].push_back(item1);
                item_pos_in_group_vector[item1] = group_items_indices[grp2_idx].size() - 1;

                group_items_indices[grp1_idx].push_back(item2);
                item_pos_in_group_vector[item2] = group_items_indices[grp1_idx].size() - 1;

                if (new_var < best_var) {
                    best_var = new_var;
                    best_assignment = assignment_array;
                }
            }
        }
    }

    // Output best assignment found
    for (int i = 0; i < N_items_global; ++i) {
        std::cout << best_assignment[i] << (i == N_items_global - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
