            if (group_items_indices[g].empty() || group_items_indices[heaviest_grp].empty()) continue;
            char res = perform_query_actual(group_items_indices[g], group_items_indices[heaviest_grp]);
            if (res == '>') {
                heaviest_grp = g;
            }
        }

        if (queries_made >= Q_total_global) break;

        // Find lightest group
        int lightest_grp = (heaviest_grp == 0) ? 1 : 0;
        for (int g = 0; g < D_groups_global && queries_made < Q_total_global; g++) {
            if (g == heaviest_grp) continue;
            if (group_items_indices[g].empty()) continue;
            if (group_items_indices[lightest_grp].empty()) { lightest_grp = g; continue; }
            char res = perform_query_actual(group_items_indices[g], group_items_indices[lightest_grp]);
            if (res == '<') {
                lightest_grp = g;
            }
        }

        if (queries_made >= Q_total_global) break;
        if (heaviest_grp == lightest_grp) break;

        // Verify they're actually different (compare directly)
        if (queries_made < Q_total_global) {
            char verify = perform_query_actual(group_items_indices[heaviest_grp], group_items_indices[lightest_grp]);
            if (verify == '=') break; // already balanced
            if (verify == '<') {
                std::swap(heaviest_grp, lightest_grp);
            }
        }

        // Now swap: move an item from heavy to light
        // Try the item from heaviest group that best corrects the imbalance
        // Use estimated weights to pick the best candidate
        long long target_w = (group_sums_array[heaviest_grp] - group_sums_array[lightest_grp]) / 2;
        int best_item = -1;
        long long best_diff = LLONG_MAX;
        for (int item_idx : group_items_indices[heaviest_grp]) {
            long long diff = std::abs(estimated_weights[item_idx] - target_w);
            if (diff < best_diff) {
                best_diff = diff;
                best_item = item_idx;
            }
        }

        if (best_item == -1) break;

        // Move best_item from heaviest to lightest
        int item_to_move = best_item;
        int old_grp = heaviest_grp;
        int new_grp = lightest_grp;

        assignment_array[item_to_move] = new_grp;
        group_sums_array[old_grp] -= estimated_weights[item_to_move];
        group_sums_array[new_grp] += estimated_weights[item_to_move];

        int pos = item_pos_in_group_vector[item_to_move];
        int last = group_items_indices[old_grp].back();
        if (item_to_move != last) {
            group_items_indices[old_grp][pos] = last;
            item_pos_in_group_vector[last] = pos;
        }
        group_items_indices[old_grp].pop_back();
        group_items_indices[new_grp].push_back(item_to_move);
        item_pos_in_group_vector[item_to_move] = group_items_indices[new_grp].size() - 1;
    }

    // Update best assignment if refinement improved things
    current_sum_sq_group_totals = 0;
    for (long long s : group_sums_array) {
        current_sum_sq_group_totals += static_cast<double>(s) * s;
    }
    current_var = calculate_variance_from_sums(current_sum_sq_group_totals, static_cast<double>(total_sum_est_val), D_groups_global);
    if (current_var < best_var) {
        best_var = current_var;
        best_assignment = assignment_array;
    }

    // Exhaust remaining queries
    int dummy_item_0_idx = 0;
    int dummy_item_1_idx = 1;
    while(queries_made < Q_total_global) {
        perform_query_actual({dummy_item_0_idx}, {dummy_item_1_idx});
        dummy_item_1_idx = (dummy_item_1_idx + 1) % N_items_global;
        if (dummy_item_1_idx == dummy_item_0_idx) {
            dummy_item_1_idx = (dummy_item_1_idx + 1) % N_items_global;
        }
    }

    // Output best assignment found
    for (int i = 0; i < N_items_global; ++i) {
        std::cout << best_assignment[i] << (i == N_items_global - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
