        int group_idx = 0;
        int direction = 1;
        for (int i = 0; i < N_items_global; i++) {
            int item = items_sorted_desc[i];
            assignment[item] = group_idx;
            sums[group_idx] += estimated_weights[item];
            groups[group_idx].push_back(item);
            group_idx += direction;
            if (group_idx >= D_groups_global) { group_idx = D_groups_global - 1; direction = -1; }
            else if (group_idx < 0) { group_idx = 0; direction = 1; }
        }
    };

    auto generate_lpt = [&](std::vector<int>& assignment, std::vector<long long>& sums, std::vector<std::vector<int>>& groups) {
        assignment.assign(N_items_global, 0);
        sums.assign(D_groups_global, 0);
        groups.assign(D_groups_global, std::vector<int>());
        for (int i = 0; i < N_items_global; i++) {
            int item = items_sorted_desc[i];
            int best_grp = 0;
            long long min_sum = sums[0];
            for (int j = 1; j < D_groups_global; j++) {
                if (sums[j] < min_sum) { min_sum = sums[j]; best_grp = j; }
            }
            assignment[item] = best_grp;
            sums[best_grp] += estimated_weights[item];
            groups[best_grp].push_back(item);
        }
    };

    // Run SA from a given starting solution
    auto run_sa = [&](std::vector<int>& assignment, std::vector<long long>& sums,
                      std::vector<std::vector<int>>& groups, double time_budget_ms) {
        if (D_groups_global <= 1 || N_items_global <= 0) return;

        double current_sum_sq = 0;
        for (long long s : sums) {
            current_sum_sq += static_cast<double>(s) * s;
        }
        double current_var = calculate_variance_from_sums(current_sum_sq, static_cast<double>(total_sum_est_val), D_groups_global);

        if (current_var < best_var) {
            best_var = current_var;
            best_assignment = assignment;
        }

        double T_initial_sa = std::max(1.0, current_var * 0.1);
        if (current_var < 1e-9) {
            T_initial_sa = std::max(1.0, static_cast<double>(total_sum_est_val) / std::max(1, N_items_global) * 0.1);
        }
        double T = T_initial_sa;
        double T_min = 1e-10;

        std::vector<int> item_pos(N_items_global);
        for (int g = 0; g < D_groups_global; g++) {
            for (int pos = 0; pos < (int)groups[g].size(); pos++) {
                item_pos[groups[g][pos]] = pos;
            }
        }

        auto sa_start = std::chrono::steady_clock::now();
        int iters = 0;
        const int CHECK_INTERVAL = 512;

        while (true) {
            iters++;
            if (iters % CHECK_INTERVAL == 0) {
                auto now = std::chrono::steady_clock::now();
                double elapsed = std::chrono::duration_cast<std::chrono::microseconds>(now - sa_start).count() / 1000.0;
                if (elapsed >= time_budget_ms) break;
                if (std::chrono::duration_cast<std::chrono::milliseconds>(now - program_start_time) >= time_limit_ms) break;
                double progress = elapsed / time_budget_ms;
                if (progress > 1.0) progress = 1.0;
                T = T_initial_sa * std::pow(T_min / T_initial_sa, progress);
            }

            if (T < 1e-15 && current_var < 1.0 + 1e-9) break;

            int move_choice = rng_engine() % 10;

            if (move_choice < 4) {
                // GUIDED RELOCATE
                int heavy_grp = 0, light_grp = 0;
                long long max_sum = sums[0], min_sum = sums[0];
                for (int g = 1; g < D_groups_global; g++) {
                    if (sums[g] > max_sum) { max_sum = sums[g]; heavy_grp = g; }
                    if (sums[g] < min_sum) { min_sum = sums[g]; light_grp = g; }
                }
                if (heavy_grp == light_grp || groups[heavy_grp].empty()) continue;

                long long target_w = (max_sum - min_sum) / 2;
                int best_item_local = -1;
                long long best_diff_local = LLONG_MAX;
                for (int item_idx : groups[heavy_grp]) {
                    long long diff = std::abs(estimated_weights[item_idx] - target_w);
                    if (diff < best_diff_local) { best_diff_local = diff; best_item_local = item_idx; }
                }
                if (best_item_local == -1) continue;

                int item_to_move = best_item_local;
                long long item_w = estimated_weights[item_to_move];

                long long old_A = sums[heavy_grp], old_B = sums[light_grp];
                long long new_A = old_A - item_w, new_B = old_B + item_w;

                double new_sum_sq = current_sum_sq;
                new_sum_sq -= (double)old_A*old_A + (double)old_B*old_B;
                new_sum_sq += (double)new_A*new_A + (double)new_B*new_B;
                double new_var = calculate_variance_from_sums(new_sum_sq, (double)total_sum_est_val, D_groups_global);

                double delta = new_var - current_var;
                if (delta < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta / T))) {
                    current_var = new_var;
                    current_sum_sq = new_sum_sq;
                    sums[heavy_grp] = new_A;
                    sums[light_grp] = new_B;
                    assignment[item_to_move] = light_grp;

                    int pos = item_pos[item_to_move];
                    int last = groups[heavy_grp].back();
                    if (item_to_move != last) { groups[heavy_grp][pos] = last; item_pos[last] = pos; }
                    groups[heavy_grp].pop_back();
                    groups[light_grp].push_back(item_to_move);
                    item_pos[item_to_move] = groups[light_grp].size() - 1;

                    if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
                }
            } else if (move_choice < 6) {
                // GUIDED SWAP
                int heavy_grp = 0, light_grp = 0;
                long long max_sum = sums[0], min_sum = sums[0];
                for (int g = 1; g < D_groups_global; g++) {
                    if (sums[g] > max_sum) { max_sum = sums[g]; heavy_grp = g; }
                    if (sums[g] < min_sum) { min_sum = sums[g]; light_grp = g; }
                }
                if (heavy_grp == light_grp || groups[heavy_grp].empty() || groups[light_grp].empty()) continue;

                long long target_diff = (max_sum - min_sum) / 2;
                int best_h = -1, best_l = -1;
                long long best_diff_local = LLONG_MAX;
                int h_samples = std::min((int)groups[heavy_grp].size(), 8);
                int l_samples = std::min((int)groups[light_grp].size(), 8);

                for (int hi = 0; hi < h_samples; hi++) {
                    int h_item = groups[heavy_grp][hi < (int)groups[heavy_grp].size() ? hi : rng_engine() % groups[heavy_grp].size()];
                    for (int li = 0; li < l_samples; li++) {
                        int l_item = groups[light_grp][li < (int)groups[light_grp].size() ? li : rng_engine() % groups[light_grp].size()];
                        long long w_diff = estimated_weights[h_item] - estimated_weights[l_item];
                        long long diff = std::abs(w_diff - target_diff);
                        if (diff < best_diff_local && w_diff > 0) { best_diff_local = diff; best_h = h_item; best_l = l_item; }
                    }
                }
                if (best_h == -1 || best_l == -1) continue;

                long long w1 = estimated_weights[best_h], w2 = estimated_weights[best_l];
                long long old1 = sums[heavy_grp], old2 = sums[light_grp];
                long long new1 = old1 - w1 + w2, new2 = old2 - w2 + w1;

                double new_sum_sq = current_sum_sq;
                new_sum_sq -= (double)old1*old1 + (double)old2*old2;
                new_sum_sq += (double)new1*new1 + (double)new2*new2;
                double new_var = calculate_variance_from_sums(new_sum_sq, (double)total_sum_est_val, D_groups_global);

                double delta = new_var - current_var;
                if (delta < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta / T))) {
                    current_var = new_var;
                    current_sum_sq = new_sum_sq;
                    sums[heavy_grp] = new1;
                    sums[light_grp] = new2;
                    assignment[best_h] = light_grp;
                    assignment[best_l] = heavy_grp;

                    int pos1 = item_pos[best_h];
                    int back1 = groups[heavy_grp].back();
                    if (best_h != back1) { groups[heavy_grp][pos1] = back1; item_pos[back1] = pos1; }
                    groups[heavy_grp].pop_back();

                    int pos2 = item_pos[best_l];
                    int back2 = groups[light_grp].back();
                    if (best_l != back2) { groups[light_grp][pos2] = back2; item_pos[back2] = pos2; }
                    groups[light_grp].pop_back();

                    groups[light_grp].push_back(best_h);
                    item_pos[best_h] = groups[light_grp].size() - 1;
                    groups[heavy_grp].push_back(best_l);
                    item_pos[best_l] = groups[heavy_grp].size() - 1;

                    if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
                }
            } else if (move_choice < 8) {
                // RANDOM RELOCATE
                int item_to_move = item_dist(rng_engine);
                int old_grp = assignment[item_to_move];
                int new_grp = group_dist(rng_engine);
                if (new_grp == old_grp) continue;

                long long item_w = estimated_weights[item_to_move];
                long long old_A = sums[old_grp], old_B = sums[new_grp];
                long long new_A = old_A - item_w, new_B = old_B + item_w;

                double new_sum_sq = current_sum_sq;
                new_sum_sq -= (double)old_A*old_A + (double)old_B*old_B;
                new_sum_sq += (double)new_A*new_A + (double)new_B*new_B;
                double new_var = calculate_variance_from_sums(new_sum_sq, (double)total_sum_est_val, D_groups_global);

                double delta = new_var - current_var;
                if (delta < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta / T))) {
                    current_var = new_var;
                    current_sum_sq = new_sum_sq;
                    sums[old_grp] = new_A;
                    sums[new_grp] = new_B;
                    assignment[item_to_move] = new_grp;

                    int pos = item_pos[item_to_move];
                    int last = groups[old_grp].back();
                    if (item_to_move != last) { groups[old_grp][pos] = last; item_pos[last] = pos; }
                    groups[old_grp].pop_back();
                    groups[new_grp].push_back(item_to_move);
                    item_pos[item_to_move] = groups[new_grp].size() - 1;

                    if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
                }
            } else {
                // RANDOM SWAP
                int grp1 = group_dist(rng_engine), grp2 = group_dist(rng_engine);
                if (grp1 == grp2 || groups[grp1].empty() || groups[grp2].empty()) continue;

                int item1 = groups[grp1][rng_engine() % groups[grp1].size()];
                int item2 = groups[grp2][rng_engine() % groups[grp2].size()];
                long long w1 = estimated_weights[item1], w2 = estimated_weights[item2];

                long long old1 = sums[grp1], old2 = sums[grp2];
                long long new1 = old1 - w1 + w2, new2 = old2 - w2 + w1;

                double new_sum_sq = current_sum_sq;
                new_sum_sq -= (double)old1*old1 + (double)old2*old2;
                new_sum_sq += (double)new1*new1 + (double)new2*new2;
                double new_var = calculate_variance_from_sums(new_sum_sq, (double)total_sum_est_val, D_groups_global);

                double delta = new_var - current_var;
                if (delta < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta / T))) {
                    current_var = new_var;
                    current_sum_sq = new_sum_sq;
                    sums[grp1] = new1;
                    sums[grp2] = new2;
                    assignment[item1] = grp2;
                    assignment[item2] = grp1;

                    int pos1 = item_pos[item1];
                    int back1 = groups[grp1].back();
                    if (item1 != back1) { groups[grp1][pos1] = back1; item_pos[back1] = pos1; }
                    groups[grp1].pop_back();

                    int pos2 = item_pos[item2];
                    int back2 = groups[grp2].back();
                    if (item2 != back2) { groups[grp2][pos2] = back2; item_pos[back2] = pos2; }
                    groups[grp2].pop_back();

                    groups[grp2].push_back(item1);
                    item_pos[item1] = groups[grp2].size() - 1;
                    groups[grp1].push_back(item2);
                    item_pos[item2] = groups[grp1].size() - 1;

                    if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
                }
            }
        }
    };

    // Multi-start: run SA from different starting solutions
    // First: snake start
    {
        std::vector<int> assignment;
        std::vector<long long> sums;
        std::vector<std::vector<int>> groups;
        generate_snake(assignment, sums, groups);
        run_sa(assignment, sums, groups, 800.0);
    }

    // Second: LPT start
    {
        std::vector<int> assignment;
        std::vector<long long> sums;
        std::vector<std::vector<int>> groups;
        generate_lpt(assignment, sums, groups);

        auto now = std::chrono::steady_clock::now();
        double remaining_ms = 1850.0 - std::chrono::duration_cast<std::chrono::microseconds>(now - program_start_time).count() / 1000.0;
        if (remaining_ms > 50) {
            run_sa(assignment, sums, groups, remaining_ms - 20);
        }
    }

    // Output best assignment found
    for (int i = 0; i < N_items_global; ++i) {
        std::cout << best_assignment[i] << (i == N_items_global - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
